SELECT count(*) FROM role_type, cast_info, name, aka_name, char_name, title, movie_companies WHERE cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id;